// =============================================================================
// Validate the incoming PDF URL.
// Niveshaay receives links from NSE and BSE only. We harden against arbitrary
// URLs (SSRF, phishing PDFs, non-PDF payloads) by checking host + extension.
// =============================================================================

const body = $input.first().json.body || $input.first().json;
const pdf_url = (body?.pdf_url || '').trim();

if (!pdf_url) {
  throw new Error("Missing required field 'pdf_url' in request body.");
}

let parsed;
try {
  parsed = new URL(pdf_url);
} catch (e) {
  throw new Error(`Invalid URL format: ${pdf_url}`);
}

if (!['http:', 'https:'].includes(parsed.protocol)) {
  throw new Error(`Unsupported protocol: ${parsed.protocol}. Use http or https.`);
}

const allowedHosts = [
  'bseindia.com',
  'www.bseindia.com',
  'nseindia.com',
  'www.nseindia.com',
  'archives.nseindia.com',
  'nsearchives.nseindia.com'
];

const hostnameAllowed = allowedHosts.some(h => parsed.hostname === h || parsed.hostname.endsWith('.' + h));
if (!hostnameAllowed) {
  throw new Error(`URL must be from BSE or NSE. Got host: ${parsed.hostname}`);
}

if (!parsed.pathname.toLowerCase().endsWith('.pdf')) {
  throw new Error('URL must point to a .pdf file');
}

return [{
  json: {
    pdf_url,
    host: parsed.hostname,
    received_at: new Date().toISOString()
  }
}];

// =============================================================================
// Parse Gemini's response.
// The Gemini API wraps the model output in candidates[0].content.parts[0].text.
// Because we set responseMimeType=application/json, the text is already a
// JSON string. We parse + handle the 'no pnl found' edge case.
// =============================================================================

const response = $input.first().json;

if (response.error) {
  throw new Error(`Gemini API error: ${response.error.message || JSON.stringify(response.error)}`);
}

const candidates = response.candidates;
if (!candidates || candidates.length === 0) {
  throw new Error('Gemini returned no candidates. Possible safety block or empty response.');
}

const candidate = candidates[0];
const rawText = candidate?.content?.parts?.[0]?.text?.trim();

if (!rawText) {
  throw new Error('Gemini response missing content.parts[0].text');
}

// Handle the explicit 'no pnl found' contract from the prompt.
if (/^no\s+pnl\s+found/i.test(rawText)) {
  return [{
    json: {
      success: false,
      reason: 'no_pnl_found',
      message: 'The document does not contain a recognizable Profit & Loss statement.'
    }
  }];
}

// Strip code fences if model returned ```json ... ```
const cleaned = rawText
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/\s*```\s*$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse Gemini JSON. Raw output: ${cleaned.slice(0, 500)}...`);
}

// Basic schema sanity
if (!parsed.company_name || !parsed.quarter_type || !parsed.row1) {
  throw new Error('Gemini JSON missing required fields (company_name / quarter_type / row1)');
}

const expectedCols = parsed.quarter_type === 'extended' ? 6 : 4;
if (parsed.row1.length !== expectedCols) {
  throw new Error(`Row column count mismatch. Expected ${expectedCols} for ${parsed.quarter_type}, got ${parsed.row1.length}.`);
}

// Token usage (cost-tracking signal — surfaced to the client)
const usage = response.usageMetadata || {};

return [{
  json: {
    success: true,
    data: parsed,
    meta: {
      model_used: response.modelVersion || 'gemini-2.5-flash',
      prompt_tokens: usage.promptTokenCount || 0,
      completion_tokens: usage.candidatesTokenCount || 0,
      total_tokens: usage.totalTokenCount || 0,
      finish_reason: candidate.finishReason || 'unknown'
    }
  }
}];

// =============================================================================
// Math validation layer.
// Recomputes margins/EBITDA/PAT-style metrics from raw rows and flags any
// discrepancies > 1 paisa. Niveshaay's analysts can't trust a JSON they don't
// re-prove, so we expose 'validation' metadata for every response.
// =============================================================================

const input = $input.first().json;

if (!input.success) {
  // Pass through non-success states (e.g., 'no_pnl_found') without validation.
  return [{ json: input }];
}

const data = input.data;
const rows = Object.entries(data)
  .filter(([k]) => /^row\d+$/.test(k))
  .sort(([a], [b]) => parseInt(a.replace('row', '')) - parseInt(b.replace('row', '')))
  .map(([, v]) => v);

const header = rows[0];
const dataCols = header.length - 1;
const issues = [];

const num = (s) => {
  if (s === '' || s === undefined || s === null) return null;
  const cleaned = String(s).replace(/%/g, '').replace(/,/g, '').trim();
  if (cleaned === '' || cleaned === '-') return 0;
  const n = parseFloat(cleaned);
  return Number.isFinite(n) ? n : null;
};

const findRow = (label) => rows.find(r => String(r[0]).trim().toLowerCase() === label.toLowerCase());

const revenue = findRow('Revenue');
const ebitda = findRow('EBITDA');
const ebitdaMargin = findRow('EBITDA Margin');
const pat = findRow('PAT');
const patMargin = findRow('PAT Margin');
const grossProfit = findRow('Gross Profit');
const gpMargin = findRow('Gross Profit Margin');

const checkMargin = (numerator, denominator, marginRow, label) => {
  if (!numerator || !denominator || !marginRow) return;
  for (let i = 1; i <= dataCols; i++) {
    const n = num(numerator[i]);
    const d = num(denominator[i]);
    const m = num(marginRow[i]);
    if (n === null || d === null || m === null || d === 0) continue;
    const expected = (n / d) * 100;
    const diff = Math.abs(expected - m);
    if (diff > 0.5) {
      issues.push({
        row: label,
        column: header[i],
        expected: expected.toFixed(2) + '%',
        got: m.toFixed(2) + '%',
        diff_pp: diff.toFixed(2)
      });
    }
  }
};

checkMargin(grossProfit, revenue, gpMargin, 'Gross Profit Margin');
checkMargin(ebitda, revenue, ebitdaMargin, 'EBITDA Margin');
checkMargin(pat, revenue, patMargin, 'PAT Margin');

return [{
  json: {
    ...input,
    validation: {
      passed: issues.length === 0,
      issues_count: issues.length,
      issues
    }
  }
}];

// =============================================================================
// Centralized error normalizer for any node that wires into this branch.
// =============================================================================

const raw = $input.first().json;

const message =
  raw?.error?.message ||
  raw?.message ||
  (typeof raw === 'string' ? raw : null) ||
  'Unknown error occurred while processing the PDF.';

const statusCode =
  raw?.error?.statusCode ||
  raw?.statusCode ||
  (message.toLowerCase().includes('invalid url') ? 400 :
   message.toLowerCase().includes('missing') ? 400 :
   message.toLowerCase().includes('too large') ? 413 :
   message.toLowerCase().includes('not from bse') ? 400 :
   500);

return [{
  json: {
    success: false,
    error: {
      message,
      status: statusCode,
      timestamp: new Date().toISOString()
    }
  }
}];
